// src/App.jsx
import React, { createContext, useContext, useState, useEffect } from 'react';
import { db } from './utils/firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  doc, 
  updateDoc, 
  query, 
  orderBy, 
  serverTimestamp 
} from 'firebase/firestore';

const AppContext = createContext();

export const bus = {
  listeners: {},
  on(event, cb) {
    if (!this.listeners[event]) this.listeners[event] = [];
    this.listeners[event].push(cb);
    return () => { this.listeners[event] = this.listeners[event].filter(l => l !== cb); };
  },
  emit(event, data) {
    if (this.listeners[event]) this.listeners[event].forEach(cb => cb(data));
  }
};

export function AppProvider({ children }) {
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);

  // Live Synchronizer from Cloud Firestore
  useEffect(() => {
    const q = query(collection(db, "complaints"), orderBy("reportedAt", "desc"));
    
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const liveComplaints = snapshot.docs.map(docSnap => {
        const data = docSnap.data();
        return {
          id: docSnap.id, // Firestore Generated Document Unique ID
          ...data,
          // Hydrate JS timestamps from Firestore server timestamps safely
          reportedAt: data.reportedAt?.toDate() || new Date(),
          resolvedAt: data.resolvedAt ? data.resolvedAt.toDate() : null
        };
      });
      setComplaints(liveComplaints);
      setLoading(false);
    }, (error) => {
      console.error("Firestore live sync collection fetch error: ", error);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  // Post entry directly inside cloud storage collections
  const addComplaint = async (newC) => {
    try {
      const ticketId = `TKT-${String(complaints.length + 1001)}`;
      const payload = {
        customTicketId: ticketId,
        status: 'NEW',
        reportedAt: serverTimestamp(),
        area: newC.area || 'Platform 1',
        gtype: newC.gtype,
        emoji: newC.emoji || '🗑️',
        severity: newC.severity || 'medium',
        lat: parseFloat(newC.lat),
        lng: parseFloat(newC.lng),
        desc: newC.desc || '',
        reportedBy: newC.reportedBy || 'Citizen (App)',
        station: newC.station, // { id, name, code, zone }
        vendor: newC.vendor || null, // default unassigned
        cleanerStatus: null,
        assignedTo: null,
        resolutionMins: null,
        resolvedAt: null
      };

      await addDoc(collection(db, "complaints"), payload);
      bus.emit('NEW_COMPLAINT', { id: ticketId, gtype: newC.gtype });
    } catch (e) {
      console.error("Error creating document entry inside Firestore: ", e);
    }
  };

  // Cross-portal mutation updates execution
  const updateComplaint = async (docId, fields) => {
    try {
      const docRef = doc(db, "complaints", docId);
      const updatePayload = { ...fields };
      
      // Inject timestamp if step transitions to closed state
      if (fields.status === 'COMPLETED') {
        updatePayload.resolvedAt = new Date();
      }

      await updateDoc(docRef, updatePayload);
    } catch (e) {
      console.error(`Failed executing transaction state over doc ${docId}: `, e);
    }
  };

  return (
    <AppContext.Provider value={{ complaints, addComplaint, updateComplaint, loading }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  return useContext(AppContext);
}

// Client View Router Switch Engine
export default function App() {
  const [route, setRoute] = useState(window.location.pathname);

  useEffect(() => {
    const handleLocationChange = () => setRoute(window.location.pathname);
    window.addEventListener('popstate', handleLocationChange);
    return () => window.removeEventListener('popstate', handleLocationChange);
  }, []);

  const navigate = (path) => {
    window.history.pushState({}, '', path);
    setRoute(path);
  };

  return (
    <AppProvider>
      {/* Route Switch Control Matrix Overlay */}
      <div style={{ position: 'fixed', top: 12, right: 12, zIndex: 9999, display: 'flex', gap: 6, background: 'rgba(10,22,40,0.85)', padding: '5px 8px', borderRadius: 20, backdropFilter: 'blur(4px)' }}>
        <button onClick={() => navigate('/')} style={{ background: route === '/' ? '#1565C0' : 'transparent', color: '#fff', border: 'none', padding: '4px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>Grievance App</button>
        <button onClick={() => navigate('/vendor')} style={{ background: route === '/vendor' ? '#1565C0' : 'transparent', color: '#fff', border: 'none', padding: '4px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>Vendor Portal</button>
        <button onClick={() => navigate('/admin')} style={{ background: route === '/admin' ? '#1565C0' : 'transparent', color: '#fff', border: 'none', padding: '4px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>Admin Command</button>
        <button onClick={() => navigate('/cleaner')} style={{ background: route === '/cleaner' ? '#1565C0' : 'transparent', color: '#fff', border: 'none', padding: '4px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>Field Force</button>
      </div>
      <RenderActiveRoute currentPath={route} />
    </AppProvider>
  );
}

function RenderActiveRoute({ currentPath }) {
  const { loading } = useApp();

  if (loading) {
    return (
      <div style={{ display: 'flex', height: '100vh', alignItems: 'center', justifyContent: 'center', background: '#F7F9FC', fontFamily: 'sans-serif', color: '#546E7A' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 24, fontWeight: 'bold', marginBottom: 8, color: '#0A1628' }}>Connecting Cloud Network...</div>
          <div>Initializing GRWMS Persistence Layer Engines</div>
        </div>
      </div>
    );
  }

  if (currentPath === '/vendor') {
    const VendorPortal = require('./pages/vendor/VendorPortal').default;
    return <VendorPortal />;
  }
  if (currentPath === '/admin') {
    const AdminPortal = require('./pages/admin/AdminPortal').default;
    return <AdminPortal />;
  }
  if (currentPath === '/cleaner') {
    const CleanerPortal = require('./pages/cleaner/CleanerPortal').default;
    return <CleanerPortal />;
  }
  const UserPortal = require('./pages/user/UserPortal').default;
  return <UserPortal />;
}
